// Parse et log la sortie de escalade.py
const stdout = $input.item.json.stdout || '';
const stderr = $input.item.json.stderr || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Extraire les IPs escaladées depuis le stdout
const escaladeMatches = stdout.matchAll(/==> Escalade IP ([\d.]+) \| score (\d+)\/100/g);
const escaladedIPs = [];
for (const m of escaladeMatches) {
  escaladedIPs.push({ ip: m[1], score: parseInt(m[2]) });
}

// Log résumé
const summaryMatch = stdout.match(/Résumé : (\d+) IP\(s\) escaladée\(s\), (\d+) ignorée/);
const escalated = summaryMatch ? parseInt(summaryMatch[1]) : 0;
const skipped = summaryMatch ? parseInt(summaryMatch[2]) : 0;

console.log(`[escalade] exitCode=${exitCode} | escalated=${escalated} | skipped=${skipped}`);
if (stderr) console.error('[escalade stderr]', stderr.substring(0, 500));

return [{
  json: {
    stdout,
    stderr,
    exitCode,
    escalated,
    skipped,
    escaladedIPs,
    timestamp: new Date().toISOString(),
    hasEscaladedIPs: escaladedIPs.length > 0
  }
}];
